class Solution {
public:
    int maxTaskAssign(vector<int>& tasks, vector<int>& workers, int pills, int strength) {
        sort(tasks.begin(), tasks.end());
        sort(workers.begin(), workers.end());
        int low = 0, high = min(tasks.size(), workers.size());
        while (low < high) {
            int mid = (low + high + 1) / 2;
            if (canAssign(tasks, workers, pills, strength, mid)) {
                low = mid;
            } else {
                high = mid - 1;
            }
        }
        return low;
    }

    bool canAssign(vector<int>& tasks, vector<int>& workers, int pills, int strength, int k) {
        int i = k - 1, j = workers.size() - 1;
        int pillUsed = 0;
        while (i >= 0 && j >= 0) {
            if (workers[j] >= tasks[i]) {
                i--;
                j--;
            } else if (pillUsed < pills && workers[j] + strength >= tasks[i]) {
                pillUsed++;
                i--;
                j--;
            } else {
                return false;
            }
        }
        return i < 0;
    }
};

